selector_to_html = {"a[href=\"#data-path-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Data path setup<a class=\"headerlink\" href=\"#data-path-setup\" title=\"Link to this heading\">#</a></h2><p>We set 2 path variables:</p>", "a[href=\"#first-registration-run\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">First registration run<a class=\"headerlink\" href=\"#first-registration-run\" title=\"Link to this heading\">#</a></h2><p>If you ever get errors like</p>", "a[href=\"#load-a-data-file-to-examine\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Load a data file to examine<a class=\"headerlink\" href=\"#load-a-data-file-to-examine\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#difference-of-gaussian-blur\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Difference of Gaussian Blur<a class=\"headerlink\" href=\"#difference-of-gaussian-blur\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#run-registration-with-mesmerize-core\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Run registration with <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code><a class=\"headerlink\" href=\"#run-registration-with-mesmerize-core\" title=\"Link to this heading\">#</a></h3><p>See the mesmerize-core <a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/functions.html\">utility docs</a> for more information on batch creation.</p>", "a[href=\"#evaluate-motion-correction-outputs-with-mesmerize-core-api\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Evaluate motion correction outputs with <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> API<a class=\"headerlink\" href=\"#evaluate-motion-correction-outputs-with-mesmerize-core-api\" title=\"Link to this heading\">#</a></h2><p>mesmerize-core offers an easy <a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/mcorr.html\">API</a> to retrieve results from the batch dataframe.</p>", "a[href=\"#side-by-side-with-fastplotlib\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Side-by-side with <code class=\"docutils literal notranslate\"><span class=\"pre\">fastplotlib</span></code><a class=\"headerlink\" href=\"#side-by-side-with-fastplotlib\" title=\"Link to this heading\">#</a></h3><p>Its helpful to zoom into specific locations of your images to see improvements.</p>", "a[href=\"#calculate-registration-metrics\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Calculate registration metrics<a class=\"headerlink\" href=\"#calculate-registration-metrics\" title=\"Link to this heading\">#</a></h1><p>The first cell iterates over our batch dataframe and collects several metrics to help distinguish which parameter varients lead to the best registration results.</p>", "a[href=\"#scaling-patches-relative-to-neuron-size\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Scaling patches relative to neuron size<a class=\"headerlink\" href=\"#scaling-patches-relative-to-neuron-size\" title=\"Link to this heading\">#</a></h2><p>The <code class=\"docutils literal notranslate\"><span class=\"pre\">generate_patch_view</span></code> function divides the image into patches the same way CaImAn will do internally.</p><p>Increasing / decreasing the <code class=\"docutils literal notranslate\"><span class=\"pre\">target_patch_size</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">overlap_fraction</span></code> parameters to examine the effect of different stride/overlap values displayed in the title.</p>", "a[href=\"#optional-use-your-own-grid-search-values\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">(Optional) Use your own grid-search values.<a class=\"headerlink\" href=\"#optional-use-your-own-grid-search-values\" title=\"Link to this heading\">#</a></h2><p>For example:</p>", "a[href=\"#registration-parameters\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Registration parameters<a class=\"headerlink\" href=\"#registration-parameters\" title=\"Link to this heading\">#</a></h1><p>The parameters are passed <strong>directly</strong> to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>, this means you need to use the same exact names for the parameters and you can use all the parameters that you can use with <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code> - because it\u2019s just passing them to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p><p>The parameters dict for a mesmerize batch item must have the following structure. Put all the parameters in a dict under a key called <strong>main</strong>. The <strong>main</strong> dict is then fed directly to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p>", "a[href=\"#optional-view-hardware-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">(optional): View hardware information<a class=\"headerlink\" href=\"#optional-view-hardware-information\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#using-metadata-to-assign-parameter-values\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Using metadata to assign parameter values<a class=\"headerlink\" href=\"#using-metadata-to-assign-parameter-values\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">plot_data_with_scalebars</span></code> will give you 3 images, at 5, 10 and 20 um.</p><p>You can use any summary images:</p>", "a[href=\"#registration\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Registration<a class=\"headerlink\" href=\"#registration\" title=\"Link to this heading\">#</a></h1><p>Correct for rigid/non-rigid movement</p>", "a[href=\"#create-the-parameters-we-pass-to-caiman\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Create the parameters we pass to CaImAn<a class=\"headerlink\" href=\"#create-the-parameters-we-pass-to-caiman\" title=\"Link to this heading\">#</a></h2><p>The above patch view looks good, so we use those values in our parameters dictionary.</p><p>You <em>can</em> also include segmentation parameters in this dictionary if you wish. This is <em>not recommmended</em> as several parameters share similar names yet perform different actions. i.e:</p>", "a[href=\"#check-for-errors-in-outputs\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Check for errors in outputs<a class=\"headerlink\" href=\"#check-for-errors-in-outputs\" title=\"Link to this heading\">#</a></h3><p>In the table header <strong>outputs</strong>, you should see</p>", "a[href=\"#create-or-load-a-batch-set\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Create or load a batch set<a class=\"headerlink\" href=\"#create-or-load-a-batch-set\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#use-the-varients-to-organize-results-to-run-multiple-batch-items\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Use the varients to organize results to run multiple batch items.<a class=\"headerlink\" href=\"#use-the-varients-to-organize-results-to-run-multiple-batch-items\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">df.iterrows()</span></code> iterates through rows and returns the numerical index and row for each iteration</p>", "a[href=\"#view-metadata\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">View metadata<a class=\"headerlink\" href=\"#view-metadata\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">lcp.get_metadata(filepath)</span></code> works on raw scanimage files and files processed through <code class=\"docutils literal notranslate\"><span class=\"pre\">lcp.save_as()</span></code></p>", "a[href=\"#define-parameter-varients\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Define parameter varients<a class=\"headerlink\" href=\"#define-parameter-varients\" title=\"Link to this heading\">#</a></h1><p>If you still see non-rigid motion in your movie, we can try increasing the scale_factor to increase our patch-size or decrease it.</p><p>More than likely you will want to decrease the scale factor to process more patches.</p>", "a[href=\"#optical-flow\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Optical Flow<a class=\"headerlink\" href=\"#optical-flow\" title=\"Link to this heading\">#</a></h2><p>Optical flow measures the movement of a pixel between two consecutive frames.</p><p><img alt=\"optical_flow\" src=\"examples/images/optical_flow.png\"/></p>", "a[href=\"#apply-the-best-parameters-to-remaining-files\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Apply the \u2018best parameters\u2019 to remaining files<a class=\"headerlink\" href=\"#apply-the-best-parameters-to-remaining-files\" title=\"Link to this heading\">#</a></h1><p>When you decide which parameter set works the best, we keep it and delete the other batch items.</p><p>Remove batch items (i.e. rows) using <code class=\"docutils literal notranslate\"><span class=\"pre\">df.caiman.remove_item(&lt;item_uuid&gt;)</span></code>. This also cleans up the output data in the batch directory.</p>", "a[href=\"#correlation-with-mean-image\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Correlation with Mean Image<a class=\"headerlink\" href=\"#correlation-with-mean-image\" title=\"Link to this heading\">#</a></h1><h2>Difference of Gaussian Blur<a class=\"headerlink\" href=\"#difference-of-gaussian-blur\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#apply-registration-using-the-same-parameters-to-the-remaining-files\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Apply registration using the same parameters to the remaining files<a class=\"headerlink\" href=\"#apply-registration-using-the-same-parameters-to-the-remaining-files\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#add-an-item-to-the-batch\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Add an item to the batch<a class=\"headerlink\" href=\"#add-an-item-to-the-batch\" title=\"Link to this heading\">#</a></h3><p>A \u201cbatch item\u201d consists of:</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
